package arch.day40;

public class Day40Exercise {

    public static void main(String[] args) {
        Runnable task = () -> System.out.println("done");
        long t0 = System.nanoTime();
        task.run();
        long t1 = System.nanoTime();
        System.out.println("elapsed_ms=" + (t1 - t0) / 1_000_000);
    }
}
